import axios from 'axios';

const backendURL = 'http://localhost:3000/api/accounts';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

export const getAllAccounts = async () => {
    try {
        const response = await axios.get(backendURL, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get all accounts error:', error);
        throw error;
    }
};

export const createAccount = async (username, password, email) => {
    try {
        const response = await axios.post(backendURL, { username, password, email });
        return response.data;
    } catch (error) {
        console.error('Create account error:', error);
        throw error;
    }
};

export const getAccount = async (id) => {
    try {
        const response = await axios.get(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get account error:', error);
        throw error;
    }
};

export const updateAccount = async (id, username, password, email) => {
    try {
        const response = await axios.put(`${backendURL}/${id}`, { username, password, email }, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update account error:', error);
        throw error;
    }
};

export const deleteAccount = async (id) => {
    try {
        const response = await axios.delete(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Delete account error:', error);
        throw error;
    }
};

export const checkUserRole = async () => {
    try {
        const response = await axios.get(`${backendURL}/check-role`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Check user role error:', error);
        throw error;
    }
};
